// FIX H6: Parseo robusto de respuesta de Claude con fallback estructurado.
const input = $input.first().json;

// Verificar que content existe y tiene al menos un bloque de tipo text
const block = input?.content?.find(b => b.type === 'text');
if (!block?.text) {
  throw new Error(`[bant] Respuesta Claude sin text block. stop_reason=${input?.stop_reason}. Payload: ${JSON.stringify(input).slice(0, 500)}`);
}

// FIX H6: Regex non-greedy para no capturar multiples objetos JSON
const match = block.text.match(/\{[\s\S]*?\}/);
if (!match) {
  throw new Error(`[bant] No se encontro JSON en respuesta Claude: ${block.text.slice(0, 500)}`);
}

let bant;
try {
  bant = JSON.parse(match[0]);
} catch (e) {
  throw new Error(`[bant] JSON invalido en respuesta Claude: ${match[0].slice(0, 300)} — Error: ${e.message}`);
}

// FIX H6: Validar esquema de respuesta
const validTiers = ['HOT', 'WARM', 'COLD'];
if (typeof bant.total !== 'number') {
  throw new Error(`[bant] Campo 'total' invalido (tipo: ${typeof bant.total}): ${JSON.stringify(bant)}`);
}
if (!validTiers.includes(bant.tier)) {
  throw new Error(`[bant] Campo 'tier' invalido (valor: ${bant.tier}): ${JSON.stringify(bant)}`);
}

// Garantizar que todos los campos numericos son numeros
bant.budget = Number(bant.budget) || 0;
bant.authority = Number(bant.authority) || 0;
bant.need = Number(bant.need) || 0;
bant.timeline = Number(bant.timeline) || 0;
bant.total = Number(bant.total) || 0;
bant.lead_id = $('Webhook - BANT Trigger').item.json.lead_id;

return [{ json: bant }];

